package com.webview.climamapcom;
import android.app.Activity;import android.os.Bundle;import android.webkit.WebSettings;import android.webkit.WebView;import android.webkit.WebViewClient;import android.webkit.WebResourceRequest;import android.net.Uri;import android.os.Build;
public class MainActivity extends Activity{private WebView webView;private static final String START_URL="https://climamap.com/";private static final String ALLOWED_HOST=Uri.parse(START_URL).getHost();protected void onCreate(Bundle b){super.onCreate(b);webView=new WebView(this);setContentView(webView);WebView.setWebContentsDebuggingEnabled(false);WebSettings s=webView.getSettings();s.setJavaScriptEnabled(true);s.setDomStorageEnabled(true);s.setLoadWithOverviewMode(true);s.setUseWideViewPort(true);s.setAllowFileAccess(false);s.setAllowContentAccess(false);s.setAllowFileAccessFromFileURLs(false);s.setAllowUniversalAccessFromFileURLs(false);s.setMixedContentMode(WebSettings.MIXED_CONTENT_NEVER_ALLOW);if(Build.VERSION.SDK_INT>=26){s.setSafeBrowsingEnabled(true);}webView.setWebViewClient(new WebViewClient(){public boolean shouldOverrideUrlLoading(WebView view,WebResourceRequest request){Uri uri=request.getUrl();String scheme=uri.getScheme();String host=uri.getHost();if(scheme==null||host==null)return true;if(!scheme.equals("https"))return true;if(!host.equals(ALLOWED_HOST))return true;return false;}});webView.loadUrl(START_URL);}public void onBackPressed(){if(webView!=null&&webView.canGoBack())webView.goBack();else super.onBackPressed();}}
